import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Claude Code Best Practices (Official Anthropic Documentation)","description":"","frontmatter":{"url":"https://code.claude.com/docs/en/best-practices","date":"2026-05-12T00:00:00.000Z","scored":"2026-05-16T00:00:00.000Z","source":"code.claude.com (Anthropic Official)","source_file":"../2026-05-12-claude-code-best-practices.md","source_tier":"O","tags":["claude-code","best-practices","session-management","scaling-patterns","failure-patterns","official"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-12-claude-code-best-practices.md","filePath":"research/ai-articles/scored/2026-05-12-claude-code-best-practices.md","lastUpdated":1779894392000}'),c={name:"research/ai-articles/scored/2026-05-12-claude-code-best-practices.md"};function d(i,t,s,n,l,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="claude-code-best-practices-official-anthropic-documentation" tabindex="-1">Claude Code Best Practices (Official Anthropic Documentation) <a class="header-anchor" href="#claude-code-best-practices-official-anthropic-documentation" aria-label="Permalink to &quot;Claude Code Best Practices (Official Anthropic Documentation)&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://code.claude.com/docs/en/best-practices" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/best-practices</a><br><strong>來源層級</strong>：O（Official Anthropic documentation）</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Anthropic 官方 Claude Code 最佳實踐文件。最有價值的是「Common Failure Patterns to Avoid」的五類模式分類（kitchen sink / over-correction / over-specified CLAUDE.md / trust-then-verify gap / infinite exploration），及 Scaling Patterns（並行 session、auto mode、fan-out）。多數原則已隱含於 cc-workspace，但命名分類提供更清晰的心智模型。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><h3 id="五大失敗模式-高價值分類" tabindex="-1">五大失敗模式（高價值分類） <a class="header-anchor" href="#五大失敗模式-高價值分類" aria-label="Permalink to &quot;五大失敗模式（高價值分類）&quot;">​</a></h3><ol><li><strong>Kitchen sink session</strong>：多任務間 context 混雜 → Fix: <code>/clear</code></li><li><strong>Correcting over and over</strong>：兩次修正失敗後 <code>/clear</code>，重寫更好的 initial prompt</li><li><strong>Over-specified CLAUDE.md</strong>：重要規則被雜訊淹沒 → ruthlessly prune</li><li><strong>Trust-then-verify gap</strong>：實作看起來對但沒有驗證 → always provide verification</li><li><strong>Infinite exploration</strong>：context 被數百個文件佔滿 → scope narrowly or use subagents</li></ol><h3 id="scaling-patterns" tabindex="-1">Scaling Patterns <a class="header-anchor" href="#scaling-patterns" aria-label="Permalink to &quot;Scaling Patterns&quot;">​</a></h3><ul><li><strong>Non-interactive mode</strong>：<code>claude -p &quot;prompt&quot;</code> 用於 CI/pre-commit hooks/scripts</li><li><strong>Parallel sessions</strong>：worktrees + desktop app + cloud（對應 bcherny 的 50-150 PRs/day）</li><li><strong>Fan out across files</strong>：<code>claude -p</code> loop 批次操作</li><li><strong>Auto mode</strong>：classifier 持續自主執行 + background safety checks</li></ul><hr><h2 id="cc-workspace-可行動性-新增-vs-現有" tabindex="-1">cc-workspace 可行動性（新增 vs 現有） <a class="header-anchor" href="#cc-workspace-可行動性-新增-vs-現有" aria-label="Permalink to &quot;cc-workspace 可行動性（新增 vs 現有）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原則</th><th>cc-workspace 現狀</th><th>新增價值</th></tr></thead><tbody><tr><td>驗證迴路</td><td>core.md R4</td><td>失敗模式 #4 命名強化</td></tr><tr><td>失敗模式分類</td><td>未明確分類</td><td>★ 五類命名 + Fix 可直接加入 output-discipline.md</td></tr><tr><td>Scaling patterns</td><td>subagent-strategy.md 部分涵蓋</td><td>★ fan-out / auto mode / non-interactive 尚未明確</td></tr><tr><td>CLAUDE.md pruning</td><td>CLAUDE.md ≤200 行</td><td>「ruthlessly prune」的明確理由補充</td></tr></tbody></table><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>五類失敗模式命名 + Scaling Patterns 尚未完整編碼進 cc-workspace；官方文件提供明確理由補充現有規則</td></tr><tr><td>B. 創新性</td><td>6/10</td><td>多數原則概念上已在 workspace；失敗模式分類法和 auto mode / fan-out 描述是邊際增量</td></tr><tr><td>C. 證據品質</td><td>9/10</td><td>Anthropic 官方文件（O-tier），最高可信度</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>提供清晰的策略與失敗模式；缺乏實作細節（hooks/settings 具體配置）</td></tr><tr><td>E. 泛化性</td><td>10/10</td><td>官方文件適用所有 Claude Code 使用者，無特化情境</td></tr><tr><td><strong>加權總分</strong></td><td><strong>8.0/10</strong></td><td>8×0.3 + 6×0.2 + 9×0.2 + 7×0.15 + 10×0.15 = 2.40+1.20+1.80+1.05+1.50</td></tr></tbody></table><p><strong>整合決策</strong>：Rule（補充失敗模式分類）+ Reference doc（官方完整文件留存）<br><strong>整合位置</strong>：</p><ul><li>失敗模式分類 → <code>.claude/rules/output-discipline.md</code> 或 <code>core.md</code> § 失敗模式</li><li>完整文件 → <code>.claude/refs/claude-code-official-best-practices.md</code>（新建 reference）</li><li>Scaling Patterns → <code>.claude/rules/subagent-strategy.md</code> § 平行 Session 策略</li></ul><p><strong>整合狀態</strong>：待實作</p><hr><h2 id="todo" tabindex="-1">TODO <a class="header-anchor" href="#todo" aria-label="Permalink to &quot;TODO&quot;">​</a></h2><ul><li>[ ] 在 <code>.claude/rules/core.md</code> 或 <code>output-discipline.md</code> 加入五類失敗模式的命名分類（Kitchen sink / Over-correction / Over-specified / Trust-then-verify gap / Infinite exploration）</li><li>[ ] 在 <code>subagent-strategy.md</code> § 平行 Session 補充 auto mode + fan-out patterns</li><li>[ ] 新建 <code>.claude/refs/claude-code-official-best-practices.md</code> 作為永久 reference link</li></ul>',23)])])}const f=e(c,[["render",d]]);export{p as __pageData,f as default};
